class Solution {
    public int maxTaskAssign(int[] tasks, int[] workers, int pills, int strength) {
        Arrays.sort(tasks);
        Arrays.sort(workers);
        int left = 0, right = pills;
        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (canAssign(tasks, workers, mid, strength)) {
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }
        return right;
    }

    private boolean canAssign(int[] tasks, int[] workers, int pills, int strength) {
        int i = tasks.length - 1, j = workers.length - 1;
        while (pills > 0 && i >= 0 && j >= 0) {
            if (workers[j] >= tasks[i]) {
                pills--;
                i--;
                j--;
            } else {
                j--;
                workers[j] += strength;
            }
        }
        return i < 0;
    }
}
